mapper.select:
SELECT id, username, real_name, phone, email, status, create_time FROM sys_user
AND is_deleted = 0
AND username LIKE CONCAT('%', #{username}, '%')
AND phone LIKE CONCAT('%', #{phone}, '%')
AND status = #{status}
ORDER BY create_time DESC LIMIT #{offset}, #{pageSize}

mapper.insert:
